  Container,
  InputAdornment,
  IconButton
} from '@mui/material';
import {
  Visibility,
  VisibilityOff,
  Email,
  Lock,
  Instagram,
  YouTube,
  Telegram as TelegramIcon
} from '@mui/icons-material';
import { Link as RouterLink } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../../contexts/AuthContext';

const Login = () => {
  const { login } = useAuth();
  const [formData, setFormData] = useState({
    email: '',
    password: ''
  });
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [videoLoaded, setVideoLoaded] = useState(false);
  const [showPlaceholder, setShowPlaceholder] = useState(true);

  const fullText = 'Nautilus Automação';

  // Preload do vídeo e timeout de segurança
  useEffect(() => {
    // Timeout de segurança progressivo: primeiro timeout em 5 segundos
    const quickTimeout = setTimeout(() => {
      if (!videoLoaded) {
        console.log('Vídeo não carregou em 5s, iniciando transição...');
        setVideoLoaded(true); // Força a transição mesmo sem carregar
      }
    }, 5000);

    // Timeout final: esconde o placeholder definitivamente em 10 segundos
    const finalTimeout = setTimeout(() => {
      setShowPlaceholder(false);
      if (!videoLoaded) {
        setVideoLoaded(true);
      }
    }, 10000);

    return () => {
      clearTimeout(quickTimeout);
      clearTimeout(finalTimeout);
    };
  }, [videoLoaded]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
    if (error) setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    if (!formData.email || !formData.password) {
      setError('Todos os campos são obrigatórios');
      setLoading(false);
      return;
    }

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/; // Regex limpo sem caracteres de controle
    if (!emailRegex.test(formData.email)) {
      setError('Formato de email inválido');
      setLoading(false);
      return;
    }

    try {
      const result = await login(formData.email, formData.password);

      if (result.success) {
        toast.success('Login realizado com sucesso!');
      } else {
        setError(result.message || 'Erro ao fazer login');
        toast.error(result.message || 'Erro ao fazer login');
      }
    } catch (error) {
      console.error('Erro no login:', error);
      setError('Erro ao fazer login. Tente novamente.');
      toast.error('Erro ao fazer login');
    } finally {
      setLoading(false);
    }
  };

  const togglePasswordVisibility = () => {
    setShowPassword(!showPassword);
  };

  const handleVideoLoad = () => {
    // Aguarda um pouco mais para garantir que o vídeo esteja realmente carregado
    setTimeout(() => {
      setVideoLoaded(true);
      setTimeout(() => {
        setShowPlaceholder(false);
      }, 500); // Delay para transição suave
    }, 1000);
  };

  return (
    <Box
      sx={{
        minHeight: '100vh',
        background: 'linear-gradient(135deg, #0a0a0a 0%, #1a1a2e 25%, #16213e 50%, #1a1a2e 75%, #0a0a0a 100%)',
        position: 'relative',
        overflow: 'hidden',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        padding: 2
      }}
    >
      {/* Placeholder animado mais sofisticado */}
      {showPlaceholder && (
        <Box
          sx={{
            position: 'absolute',
            top: 0,
            left: 0,
            width: '100vw',
            height: '100vh',
            zIndex: videoLoaded ? 1 : 3,
            opacity: videoLoaded ? 0 : 1,
            transition: 'opacity 2s ease-in-out',
            background: `
              radial-gradient(circle at 20% 80%, rgba(30, 30, 60, 0.8) 0%, transparent 50%),
              radial-gradient(circle at 80% 20%, rgba(60, 30, 60, 0.8) 0%, transparent 50%),
              radial-gradient(circle at 40% 40%, rgba(30, 60, 30, 0.6) 0%, transparent 50%),
              linear-gradient(135deg, #0a0a0a 0%, #1a1a2e 25%, #16213e 50%, #1a1a2e 75%, #0a0a0a 100%)
            `,
            backgroundSize: '400% 400%, 300% 300%, 500% 500%, 200% 200%',
            animation: 'complexGradientShift 12s ease-in-out infinite',
            '&::before': {
              content: '""',
              position: 'absolute',
              top: 0,
              left: 0,
              right: 0,
              bottom: 0,
              background: `
                repeating-linear-gradient(
                  0deg,
                  transparent,
                  transparent 2px,
                  rgba(255, 255, 255, 0.03) 2px,
                  rgba(255, 255, 255, 0.03) 4px
                ),
                repeating-linear-gradient(
                  90deg,
                  transparent,
                  transparent 2px,
                  rgba(255, 255, 255, 0.03) 2px,
                  rgba(255, 255, 255, 0.03) 4px
                )
              `,
              animation: 'scan 3s linear infinite'
            }
          }}
        >
          {/* Loading indicator sofisticado */}
          <Box
            sx={{
              position: 'absolute',
              bottom: '20%',
              left: '50%',
              transform: 'translateX(-50%)',
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              gap: 2
            }}
          >
            <Box
              sx={{
                width: '60px',
                height: '60px',
                border: '3px solid rgba(192, 192, 192, 0.2)',
                borderTop: '3px solid #C0C0C0',
                borderRadius: '50%',
                animation: 'spin 1s linear infinite',
                boxShadow: '0 0 20px rgba(192, 192, 192, 0.3)'
              }}
            />
            <Typography
              sx={{
                color: '#C0C0C0',
                fontSize: '14px',
                fontWeight: '300',
                textAlign: 'center',
                opacity: 0.8,
                animation: 'glow 2s ease-in-out infinite'
              }}
            >
              Carregando experiência...
            </Typography>
            <Box
              sx={{
                display: 'flex',
                gap: 0.5,
                '& span': {
                  width: '8px',
                  height: '8px',
                  backgroundColor: '#C0C0C0',
                  borderRadius: '50%',
                  animation: 'pulse 1.5s ease-in-out infinite',
                  '&:nth-of-type(1)': { animationDelay: '0s' },
                  '&:nth-of-type(2)': { animationDelay: '0.3s' },
                  '&:nth-of-type(3)': { animationDelay: '0.6s' }
                }
              }}
            >
              <span />
              <span />
              <span />
            </Box>
          </Box>
        </Box>
      )}

      {/* Container do vídeo com preload otimizado */}
      <Box
        sx={{
          position: 'absolute',
          top: 0,
          left: 0,
          width: '100vw',
          height: '100vh',
          zIndex: 0,
          overflow: 'hidden',
          opacity: videoLoaded ? 1 : 0,
          transition: 'opacity 2s ease-in-out',
          '& iframe': {
            position: 'absolute',
            top: '50%',
            left: '50%',
            width: '100vw',
            height: '56.25vw',
            minHeight: '100vh',
            minWidth: '177.78vh',
            transform: 'translate(-50%, -50%)',
            border: 'none',
            objectFit: 'cover'
          }
        }}
      >
        <iframe
          src="https://player.vimeo.com/video/1093368764?autoplay=1&loop=1&muted=1&background=1&controls=0&quality=hd720&autopause=0&dnt=1&title=0&byline=0&portrait=0#t=0"
          width="100%"
          height="100%"
          frameBorder="0"
          allow="autoplay; fullscreen; picture-in-picture"
          allowFullScreen
          title="Background Video"
          onLoad={handleVideoLoad}
          loading="eager"
          style={{
            filter: 'contrast(1.1) brightness(0.9) saturate(1.1)',
            willChange: 'transform, opacity'
          }}
        />
      </Box>

      {/* Overlay escuro */}
      <Box
        sx={{
          position: 'absolute',
          top: 0,
          left: 0,
          width: '100%',
          height: '100%',
          backgroundColor: 'rgba(0, 0, 0, 0.4)',
          zIndex: 2
        }}
      />

      <style>
        {`
          @keyframes complexGradientShift {
            0% {
              background-position: 0% 50%, 0% 50%, 0% 50%, 0% 50%;
            }
            25% {
              background-position: 100% 50%, 50% 100%, 25% 75%, 25% 25%;
            }
            50% {
              background-position: 100% 100%, 100% 50%, 75% 25%, 50% 50%;
            }
            75% {
              background-position: 50% 100%, 50% 0%, 100% 75%, 75% 75%;
            }
            100% {
              background-position: 0% 50%, 0% 50%, 0% 50%, 0% 50%;
            }
          }

          @keyframes scan {
            0% {
              transform: translateY(-100%);
              opacity: 0;
            }
            50% {
              opacity: 1;
            }
            100% {
              transform: translateY(100%);
              opacity: 0;
            }
          }

          @keyframes spin {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
          }

          @keyframes pulse {
            0%, 100% { 
              opacity: 0.3; 
              transform: scale(0.8); 
            }
            50% { 
              opacity: 1; 
              transform: scale(1.2); 
            }
          }

          @keyframes gradientShift {
            0% {
              background-position: 0% 50%;
            }
            50% {
              background-position: 100% 50%;
            }
            100% {
              background-position: 0% 50%;
            }
          }

          @keyframes blink {
            0%, 50% { opacity: 1; }
            51%, 100% { opacity: 0; }
          }
          @keyframes blinkDots {
            0%, 33% { opacity: 1; }
            34%, 66% { opacity: 0.5; }
            67%, 100% { opacity: 0; }
          }
          @keyframes shimmer {
            0% {
              background-position: -200% 0;
            }
            100% {
              background-position: 200% 0;
            }
          }
          @keyframes float {
            0%, 100% { transform: translateY(0px) rotate(0deg); }
            50% { transform: translateY(-10px) rotate(180deg); }
          }
          @keyframes glow {
            0%, 100% { text-shadow: 0 0 5px currentColor; }
            50% { text-shadow: 0 0 20px currentColor, 0 0 30px currentColor; }
          }
        `}
      </style>
      <Container component="main" maxWidth="xs" sx={{ zIndex: 2, position: 'relative' }}>
        <Paper 
          elevation={10} 
          sx={{
            padding: { xs: 3, sm: 4 }, 
            borderRadius: '15px', 
            background: 'rgba(0, 0, 0, 0.7)', 
            backdropFilter: 'blur(10px)',
            border: '1px solid rgba(192, 192, 192, 0.3)',
            boxShadow: '0 8px 32px 0 rgba(0, 0, 0, 0.5)'
          }}
        >
          <Box sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center', mb: 3 }}>
            <Typography variant="h4" sx={{ color: '#C0C0C0', fontWeight: 'bold', mb: 1}}>{fullText}</Typography>
          </Box>
          <Box component="form" onSubmit={handleSubmit} noValidate>
            {error && (
              <Alert 
                severity="error" 
                sx={{ 
                  mb: 2,
                  backgroundColor: 'rgba(211, 47, 47, 0.1)',
                  color: '#ff6b6b',
                  border: '1px solid rgba(211, 47, 47, 0.3)',
                  '& .MuiAlert-icon': {
                    color: '#ff6b6b'
                  }
                }}
              >
                {error}
              </Alert>
            )}

            <TextField
              margin="normal"
              required
              fullWidth
              id="email"
              label="Email"
              name="email"
              autoComplete="email"
              autoFocus
              value={formData.email}
              onChange={handleChange}
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <Email sx={{ color: '#C0C0C0' }} />
                  </InputAdornment>
                ),
                sx: { color: '#C0C0C0', '&.Mui-focused .MuiOutlinedInput-notchedOutline': { borderColor: '#C0C0C0' } }
              }}
              InputLabelProps={{
                sx: { color: '#C0C0C0' }
              }}
              sx={{ mb: 2, '& .MuiOutlinedInput-root': { '& fieldset': { borderColor: 'rgba(192, 192, 192, 0.5)' }, '&:hover fieldset': { borderColor: '#C0C0C0' } } }}
            />
            <TextField
              margin="normal"
              required
              fullWidth
              name="password"
              label="Senha"
              type={showPassword ? 'text' : 'password'}
              id="password"
              autoComplete="current-password"
              value={formData.password}
              onChange={handleChange}
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <Lock sx={{ color: '#C0C0C0' }} />
                  </InputAdornment>
                ),
                endAdornment: (
                  <InputAdornment position="end">
                    <IconButton
                      aria-label="toggle password visibility"
                      onClick={togglePasswordVisibility}
                      edge="end"
                      sx={{ color: '#C0C0C0' }}
                    >
                      {showPassword ? <VisibilityOff /> : <Visibility />}
                    </IconButton>
                  </InputAdornment>
                ),
                sx: { color: '#C0C0C0', '&.Mui-focused .MuiOutlinedInput-notchedOutline': { borderColor: '#C0C0C0' } }
              }}
              InputLabelProps={{
                sx: { color: '#C0C0C0' }
              }}
              sx={{ mb: 2, '& .MuiOutlinedInput-root': { '& fieldset': { borderColor: 'rgba(192, 192, 192, 0.5)' }, '&:hover fieldset': { borderColor: '#C0C0C0' } } }}
            />
            <Button
              type="submit"
              fullWidth
              variant="contained"
              disabled={loading}
              sx={{
                mt: 3, 
                mb: 2, 
                py: 1.5,
                background: 'rgba(0, 0, 0, 0.8)',
                border: '1px solid rgba(192, 192, 192, 0.3)',
                '&:hover': {
                  background: 'rgba(0, 0, 0, 0.9)',
                  border: '1px solid #C0C0C0'
                },
                color: '#C0C0C0',
                fontWeight: 'bold'
              }}
            >
              {loading ? <CircularProgress size={24} sx={{color: '#C0C0C0'}} /> : 'Acessar'}
            </Button>
            <Box sx={{ mt: 2, textAlign: 'center' }}>
              <Typography variant="body2" sx={{ color: '#C0C0C0' }}>
                Não tem uma conta?
                <Link component={RouterLink} to="/register" variant="body2" sx={{ color: '#C0C0C0', fontWeight: 'bold', ml: 0.5, textDecoration: 'underline' }}>
                  Registre-se
                </Link>
              </Typography>
              <Typography variant="body2" sx={{ color: '#C0C0C0', mt: 1 }}>
                Ou
                <Link component={RouterLink} to="/register?source=invite" variant="body2" sx={{ color: '#C0C0C0', fontWeight: 'bold', ml: 0.5, textDecoration: 'underline' }}>
                  Registrar com Código de Convite
                </Link>
              </Typography>
            </Box>
          </Box>
          <Box sx={{ mt: 4, display: 'flex', justifyContent: 'center', gap: 2 }}>
            <IconButton href="https://www.instagram.com/bigwhale_oficial/" target="_blank" sx={{ color: '#C0C0C0' }}>
              <Instagram />
            </IconButton>
            <IconButton href="https://www.youtube.com/@grupobigwhale_of" target="_blank" sx={{ color: '#C0C0C0' }}>
              <YouTube />
            </IconButton>
            <IconButton href="https://t.me/grupobigwhale_Of" target="_blank" sx={{ color: '#C0C0C0' }}>
              <TelegramIcon />
            </IconButton>
          </Box>
        </Paper>
      </Container>
    </Box>
  );
};

export default Login;
